// SUBMIT_CODE

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int* generateArray(int n); // Assume it's defined elsewhere

// SUBMIT_CODE


int main() {
    char input[1000];
    char output[1000];
    char result[10000] = "";

    while (fgets(input, sizeof(input), stdin) && fgets(output, sizeof(output), stdin)) {
        int n = atoi(input);

        if (n < 1 || n > 100) {
            sprintf(result + strlen(result), "Invalid TestCase %d \n", n);
            break;
        }

        int* actualOutput = generateArray(n);

        char arrStr[1000] = "[";
        for (int i = 0; i < n; i++) {
            char num[10];
            sprintf(num, "%d", actualOutput[i]);
            strcat(arrStr, num);
            if (i != n - 1) strcat(arrStr, ",");
        }
        strcat(arrStr, "]");

        // Remove whitespace from both output and arrStr
        char cleanedOutput[1000], cleanedArr[1000];
        int ci = 0, cj = 0;
        for (int i = 0; output[i]; i++)
            if (output[i] != ' ' && output[i] != '\n') cleanedOutput[ci++] = output[i];
        cleanedOutput[ci] = '\0';

        for (int i = 0; arrStr[i]; i++)
            if (arrStr[i] != ' ') cleanedArr[cj++] = arrStr[i];
        cleanedArr[cj] = '\0';

        if (strcmp(cleanedOutput, cleanedArr) == 0)
            strcat(result, "Passed\n");
        else
            strcat(result, "Failed\n");

        free(actualOutput);
    }

    printf("%s", result);
    return 0;
}

